+            // IPv6 literal: [::1]:5432
+            if let Some((bracket_host, rest)) = host_port.split_once(']') {
+                let h = bracket_host.trim_start_matches('[');
+                let p = rest
+                    .strip_prefix(':')
+                    .and_then(|s| s.parse().ok())
+                    .unwrap_or(5432u16);
